h a baseline approach and demonstrate how an LLM can use retrieved memories to generate accurate answers. Copy Code Copied Use a different Browser import sys import subprocess import pkgutil import os import json import math import random import textwrap import getpass from dataclasses import dataclass from typing import List, Dict, Any, Tuple def _install_if_missing(packages): missing = [] for package_name, import_name in packages: if pkgutil.find_loader(import_name) is None: missing.append(package_name) if missing: subprocess.check_call([sys.executable, "-m", "pip", "install", "-q"] + missing) _install_if_missing([ ("openai>=1.40.0", "openai"), ("gymnasium>=0.29.1", "gymnasium"), ("stable-baselines3>=2.3.2", "stable_baselines3"), ("numpy>=1.26.4", "numpy"), ("pandas>=2.2.2", "pandas"), ("scikit-learn>=1.5.1", "sklearn"), ("matplotlib>=3.9.0", "matplotlib"), ("tqdm>=4.66.4", "tqdm"), ]) import numpy as np import pandas as pd import gymnasium as gym from gymnasium import spaces from tqdm.auto import tqdm import matplotlib.pyplot as plt from sklearn.metrics.pairwise import cosine_similarity from stable_baselines3 import PPO from stable_baselines3.common.vec_env import DummyVecEnv from openai import OpenAI SEED = 42 random.seed(SEED) np.random.seed(SEED) try: from google.colab import userdata OPENAI_API_KEY = userdata.get("OPENAI_API_KEY") except Exception: OPENAI_API_KEY = None if not OPENAI_API_KEY: OPENAI_API_KEY = os.getenv("OPENAI_API_KEY") if not OPENAI_API_KEY: OPENAI_API_KEY = getpass.getpass("Enter OPENAI_API_KEY: ").strip() client = OpenAI(api_key=OPENAI_API_KEY) EMBED_MODEL = "text-embedding-3-small" CHAT_MODEL = "gpt-4o-mini" def chunked(xs, n): for i in range(0, len(xs), n): yield xs[i:i+n] def embed_texts(texts: List[str], model: str = EMBED_MODEL, batch_size: int = 64) -> np.ndarray: outputs = [] for batch in tqdm(list(chunked(texts, batch_size)), desc="Embedding"): resp = client.embeddings.create(model=model, input=batch) batch_vecs = [d.embedding for d in resp.data] outputs.extend(batch_vecs) arr = np.array(outputs, dtype=np.float32) norms = np.linalg.norm(arr, axis=1, keepdims=True) + 1e-12 arr = arr / norms return arr def chat_answer(question: str, retrieved_memories: List[Dict[str, Any]], model: str = CHAT_MODEL) -> str: memory_block = "
".join([f"[Memory {i+1}] {m['text']}" for i, m in enumerate(retrieved_memories)]) system = "You are a precise QA assistant. Answer the question using only the provided memories. If the memories do not contain the answer, say 'I do not know from the provided memories.'" user = f"Question: {question}

Retrieved memories:
