Answer:" resp = client.chat.completions.create( model=model, temperature=0, messages=[ {"role": "system", "content": system}, {"role": "user", "content": user}, ], ) return resp.choices[0].message.content.strip() def llm_judge_exact(question: str, gold_answer: str, predicted_answer: str, model: str = CHAT_MODEL) -> float: system = "You are a strict evaluator. Return only JSON with a single key 'score'. Use 1.0 if the predicted answer is semantically correct, 0.0 otherwise." user = json.dumps({ "question": question, "gold_answer": gold_answer, "predicted_answer": predicted_answer, }, ensure_ascii=False) resp = client.chat.completions.create( model=model, temperature=0, response_format={"type": "json_object"}, messages=[ {"role": "system", "content": system}, {"role": "user", "content": user}, ], ) txt = resp.choices[0].message.content.strip() try: obj = json.loads(txt) score = float(obj["score"]) return 1.0 if score >= 0.5 else 0.0 except Exception: return 0.0 We set up the environment required for our reinforcement learning–based memory retrieval system. We install all required libraries, import the necessary modules, and securely load the OpenAI API key for embedding and language model interactions. We also define helper functions that generate embeddings, produce answers from retrieved memories, and evaluate answers using an LLM-based judging mechanism. Copy Code Copied Use a different Browser @dataclass class MemoryItem: memory_id: int topic: str entity: str slot: str value: str text: str def build_memory_bank() -> List[MemoryItem]: entities = [ { "entity": "Astra", "topic": "robotics", "facts": { "battery": "18 hours", "sensor": "LiDAR", "country": "Japan", "release_year": "2023", "specialty": "warehouse navigation", }, }, { "entity": "Orion", "topic": "astronomy", "facts": { "telescope": "infrared array", "country": "Chile", "discovery_year": "2019", "target": "exoplanet atmospheres", "aperture": "8 meters", }, }, { "entity": "Vita", "topic": "biomedicine", "fa